module shift_reg16(
    input [15:0] d,
    input clk,
    input load,
    input shift,
    output reg [15:0] q
    );

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
    begin
        if (load)
            q <= d;
        else if (shift)
            q <= {1'b0, q[15:1]};
    end

endmodule
